      await expect(rateLimitMsg).toBeVisible({ timeout: 3000 });
    });
  });

  test.describe('2FA Flow', () => {
    test('sollte 2FA-Eingabe anzeigen wenn aktiviert', async ({ page }) => {
      await page.goto('/login');
      await page.fill('input[type="email"]', process.env.TEST_MFA_USER || '2fa@test.de');
