    const errorContent = await page.textContent('body');
    expect(errorContent).not.toContain('503'); // Raw HTTP status is bad UX
    // Should contain German message
    // expect(errorContent).toContain('Dienst nicht verfügbar'); // ideal
  });

  test('sollte 403 Forbidden korrekt behandeln', async ({ page }) => {
    await page.route('**/api/v1/admin/**', route => {
      route.fulfill({ status: 403, body: JSON.stringify({ detail: 'Forbidden' }) });
    });

    await page.goto('/admin');
    await page.waitForLoadState('networkidle');

    // Should show access denied or redirect, not crash
    const content = await page.textContent('body');
    const hasErrorHandling = 
      content?.includes('Keine Berechtigung') ||
      content?.includes('Zugriff verweigert') ||
      page.url().includes('/');  // Redirected away

    expect(hasErrorHandling).toBeTruthy();
  });

  test('sollte JSONB-Validierungsfehler (CWE-89) abfangen', async ({ page }) => {
    // Tests the SQL injection protection from CLAUDE.md Rule #9
    const maliciousPayload = "'; DROP TABLE documents; --";

    const response = await page.request.get(
      `/api/v1/documents/?search=${encodeURIComponent(maliciousPayload)}`
    );

    // Should not cause 500, should return 400 or sanitized results
    expect(response.status()).not.toBe(500);
    expect([200, 400, 422]).toContain(response.status());
  });
});
