// tests/frontend/e2e/test_multi_tenancy.spec.ts
import { test, expect, Browser } from '@playwright/test';

test.describe('Multi-Tenancy - Mandantentrennung', () => {
  test('sollte Dokumente zwischen Mandanten isolieren', async ({ browser }) => {
    // Create two separate contexts (simulating two tenants)
    const context1 = await browser.newContext();
    const context2 = await browser.newContext();

    const page1 = await context1.newPage();
    const page2 = await context2.newPage();

    // Login as tenant A
    await page1.goto('/login');
    await page1.fill('input[type="email"]', process.env.TENANT_A_EMAIL || 'tenantA@test.de');
    await page1.fill('input[type="password"]', process.env.TENANT_A_PASS || 'PassA123!');
    await page1.click('button[type="submit"]');
    await page1.waitForLoadState('networkidle');

    // Login as tenant B
    await page2.goto('/login');
    await page2.fill('input[type="email"]', process.env.TENANT_B_EMAIL || 'tenantB@test.de');
    await page2.fill('input[type="password"]', process.env.TENANT_B_PASS || 'PassB123!');
    await page2.click('button[type="submit"]');
    await page2.waitForLoadState('networkidle');

    // Get document list for tenant A
    const tenantADocs = await page1.request.get('/api/v1/documents/');
    const tenantBDocs = await page2.request.get('/api/v1/documents/');

    if (tenantADocs.ok() && tenantBDocs.ok()) {
      const docsA = await tenantADocs.json();
      const docsB = await tenantBDocs.json();

      // Document IDs should not overlap between tenants
      const idsA = new Set((docsA.items || []).map((d: { id: string }) => d.id));
      const idsB = new Set((docsB.items || []).map((d: { id: string }) => d.id));

      const intersection = [...idsA].filter(id => idsB.has(id));
      expect(intersection).toHaveLength(0);
    }

    await context1.close();
    await context2.close();
  });

  test('sollte direkten Dokumentzugriff anderer Mandanten verweigern', async ({ page }) => {
    // Login as tenant B, try to access a document ID from tenant A
    await page.goto('/login');
    await page.fill('input[type="email"]', process.env.TENANT_B_EMAIL || 'tenantB@test.de');
    await page.fill('input[type="password"]', process.env.TENANT_B_PASS || 'PassB123!');
    await page.click('button[type="submit"]');
    await page.waitForLoadState('networkidle');

    // Try to access a known tenant A document ID
    const tenantADocId = process.env.TENANT_A_DOC_ID || '00000000-0000-0000-0000-000000000001';
    const response = await page.request.get(`/api/v1/documents/${tenantADocId}`);

    // Must return 403 or 404, not the actual document
    expect([403, 404]).toContain(response.status());
  });
});

// tests/frontend/e2e/test_api_error_boundaries.spec.ts
import { test, expect } from '@playwright/test';
import path from 'path';

test.use({ storageState: path.join(__dirname, '.auth', 'user.json') });

test.describe('API Error Boundaries - Fehlerbehandlung', () => {
  test('sollte 503 Service Unavailable auf Deutsch anzeigen', async ({ page }) => {
    await page.route('**/api/v1/documents/**', route => {
      route.fulfill({ status: 503 });
    });

    await page.goto('/');
    await page.waitForLoadState('networkidle');

    // Should show German message, not raw HTTP status
    const errorContent = await page.textContent('body');
    expect(errorContent).not.toContain('503'); // Raw HTTP status is bad UX
    // Should contain German message
    // expect(errorContent).toContain('Dienst nicht verfügbar'); // ideal
  });

  test('sollte 403 Forbidden korrekt behandeln', async ({ page }) => {
    await page.route('**/api/v1/admin/**', route => {
      route.fulfill({ status: 403, body: JSON.stringify({ detail: 'Forbidden' }) });
    });

    await page.goto('/admin');
    await page.waitForLoadState('networkidle');

    // Should show access denied or redirect, not crash
    const content = await page.textContent('body');
    const hasErrorHandling = 
      content?.includes('Keine Berechtigung') ||
      content?.includes('Zugriff verweigert') ||
      page.url().includes('/');  // Redirected away

    expect(hasErrorHandling).toBeTruthy();
  });

  test('sollte JSONB-Validierungsfehler (CWE-89) abfangen', async ({ page }) => {
    // Tests the SQL injection protection from CLAUDE.md Rule #9
    const maliciousPayload = "'; DROP TABLE documents; --";

    const response = await page.request.get(
      `/api/v1/documents/?search=${encodeURIComponent(maliciousPayload)}`
    );

    // Should not cause 500, should return 400 or sanitized results
    expect(response.status()).not.toBe(500);
    expect([200, 400, 422]).toContain(response.status());
  });
});
